request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?origId)), "5a8e825c") || CONTAINS(LCASE(STR(?normId)), "5a8e825c"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?startEvent ?startName ?task ?taskName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "5a8e825c3a9a4049b67ab53c2ba7abc8" .
  ?defs tai:belongsTo ?model .
  ?defs a bboExt:Definitions .
  ?choreo tai:belongsTo ?defs .
  ?choreo a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL {
    ?startEvent a bboExt:StartEvent .
    ?startEvent tai:belongsTo ?choreo .
    OPTIONAL { ?startEvent bbo:name ?startName . }
  }
  OPTIONAL {
    ?task a bboExt:ChoreographyTask .
    ?task tai:belongsTo ?choreo .
    OPTIONAL { ?task bbo:name ?taskName . }
  }
}
LIMIT 50
